import React, { useState, useEffect, useRef } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const formatDate = (iso) => new Date(iso).toLocaleDateString('fr-FR', {
  day: 'numeric', month: 'short', year: 'numeric'
});

const getToken = () => sessionStorage.getItem('bbrs_token');
const setToken = (t) => sessionStorage.setItem('bbrs_token', t);
const clearToken = () => sessionStorage.removeItem('bbrs_token');

function LoginForm({ onLogin }) {
  const [form, setForm] = useState({ username: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await fetch(`${API_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setToken(data.token);
      onLogin(data.token, data.user);
    } catch (err) {
      setError(err.message || 'Erreur de connexion');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: '#0a0f0a', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: "'Segoe UI', sans-serif", padding: '20px' }}>
      <div style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(0,200,0,0.2)', borderRadius: '20px', padding: '50px 40px', width: '100%', maxWidth: '420px', textAlign: 'center' }}>
        <div style={{ fontSize: '2.5rem', marginBottom: '8px' }}>🔥</div>
        <h1 style={{ color: '#ffd700', fontSize: '1.6rem', fontWeight: 800, margin: '0 0 4px' }}>BBRS Morphix IT</h1>
        <p style={{ color: '#00aa00', fontSize: '0.9rem', marginBottom: '36px' }}>Espace Administrateur</p>
        {error && <div style={{ background: 'rgba(255,60,60,0.1)', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '8px', padding: '10px', color: '#ff6060', fontSize: '0.88rem', marginBottom: '20px' }}>⚠️ {error}</div>}
        <form onSubmit={handleSubmit}>
          <label style={{ display: 'block', color: '#888', fontSize: '0.8rem', textAlign: 'left', marginBottom: '6px', fontWeight: 600 }}>IDENTIFIANT</label>
          <input style={{ width: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(0,200,0,0.25)', borderRadius: '10px', padding: '12px 16px', color: '#e8e8e8', fontSize: '1rem', outline: 'none', marginBottom: '20px', boxSizing: 'border-box' }}
            type="text" placeholder="admin" value={form.username} onChange={e => setForm({ ...form, username: e.target.value })} required />
          <label style={{ display: 'block', color: '#888', fontSize: '0.8rem', textAlign: 'left', marginBottom: '6px', fontWeight: 600 }}>MOT DE PASSE</label>
          <input style={{ width: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(0,200,0,0.25)', borderRadius: '10px', padding: '12px 16px', color: '#e8e8e8', fontSize: '1rem', outline: 'none', marginBottom: '24px', boxSizing: 'border-box' }}
            type="password" placeholder="••••••••" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required />
          <button type="submit" disabled={loading} style={{ width: '100%', background: loading ? '#555' : 'linear-gradient(135deg, #00cc00, #007700)', color: '#fff', border: 'none', borderRadius: '10px', padding: '14px', fontSize: '1rem', fontWeight: 700, cursor: loading ? 'not-allowed' : 'pointer' }}>
            {loading ? '⏳ Connexion...' : '🔐 Se connecter'}
          </button>
        </form>
      </div>
    </div>
  );
}

function ArticleForm({ token, onSaved, editArticle, onCancel }) {
  const [form, setForm] = useState({
    title: editArticle?.title || '',
    description: editArticle?.description || '',
    category: editArticle?.category || 'Général',
    content: editArticle?.content || '',
    published: editArticle?.published ?? true,
  });
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const fileRef = useRef();

  const categories = ['Général', 'Tutoriel', 'Actualités', 'Sécurité', 'Réseau', 'Développement', 'Hardware', 'Cloud'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const formData = new FormData();
    Object.entries(form).forEach(([k, v]) => formData.append(k, v));
    if (file) formData.append('file', file);
    try {
      const url = editArticle ? `${API_URL}/api/admin/articles/${editArticle.id}` : `${API_URL}/api/admin/articles`;
      const res = await fetch(url, { method: editArticle ? 'PUT' : 'POST', headers: { Authorization: `Bearer ${token}` }, body: formData });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      onSaved(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const inp = { width: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(0,200,0,0.2)', borderRadius: '10px', padding: '11px 14px', color: '#e8e8e8', fontSize: '0.95rem', outline: 'none', boxSizing: 'border-box', marginBottom: '16px' };
  const lbl = { display: 'block', color: '#888', fontSize: '0.78rem', marginBottom: '6px', fontWeight: 600 };

  return (
    <div style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(0,200,0,0.15)', borderRadius: '16px', padding: '30px' }}>
      <h3 style={{ color: '#ffd700', fontSize: '1.2rem', fontWeight: 700, marginBottom: '24px' }}>{editArticle ? '✏️ Modifier' : '➕ Nouvel article'}</h3>
      {error && <div style={{ background: 'rgba(255,60,60,0.1)', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '8px', padding: '10px', color: '#ff6060', marginBottom: '16px' }}>⚠️ {error}</div>}
      <form onSubmit={handleSubmit}>
        <label style={lbl}>TITRE *</label>
        <input style={inp} value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Titre de l'article" required />
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
          <div>
            <label style={lbl}>CATÉGORIE</label>
            <select style={{ ...inp, background: '#111' }} value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>
              {categories.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <label style={lbl}>STATUT</label>
            <div style={{ ...inp, display: 'flex', alignItems: 'center', gap: '10px' }}>
              <input type="checkbox" checked={form.published} onChange={e => setForm({ ...form, published: e.target.checked })} id="pub" style={{ width: 'auto' }} />
              <label htmlFor="pub" style={{ color: form.published ? '#00cc00' : '#888', cursor: 'pointer', margin: 0 }}>{form.published ? '✅ Publié' : '⏸️ Brouillon'}</label>
            </div>
          </div>
        </div>
        <label style={lbl}>DESCRIPTION</label>
        <textarea style={{ ...inp, resize: 'vertical', minHeight: '80px' }} value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="Courte description..." />
        <label style={lbl}>CONTENU</label>
        <textarea style={{ ...inp, resize: 'vertical', minHeight: '120px' }} value={form.content} onChange={e => setForm({ ...form, content: e.target.value })} placeholder="Contenu de l'article..." />
        <label style={lbl}>FICHIER JOINT (PDF, Image, Word — max 25MB)</label>
        <div style={{ marginBottom: '20px' }}>
          <button type="button" onClick={() => fileRef.current.click()}
            style={{ background: 'rgba(0,200,0,0.1)', border: '1px dashed rgba(0,200,0,0.3)', borderRadius: '10px', padding: '16px 24px', color: '#00cc00', cursor: 'pointer', fontSize: '0.9rem', width: '100%' }}>
            {file ? `📎 ${file.name}` : editArticle?.file ? `📎 ${editArticle.file.originalname}` : '📁 Choisir un fichier...'}
          </button>
          <input ref={fileRef} type="file" style={{ display: 'none' }} accept=".pdf,.jpg,.jpeg,.png,.gif,.webp,.docx,.doc,.md,.txt,.zip,.pptx,.xlsx" onChange={e => setFile(e.target.files[0])} />
        </div>
        <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end' }}>
          {onCancel && <button type="button" onClick={onCancel} style={{ background: 'rgba(255,255,255,0.05)', color: '#aaa', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', padding: '12px 20px', cursor: 'pointer' }}>Annuler</button>}
          <button type="submit" disabled={loading} style={{ background: loading ? '#444' : 'linear-gradient(135deg, #00cc00, #007700)', color: '#fff', border: 'none', borderRadius: '10px', padding: '12px 28px', fontWeight: 700, cursor: loading ? 'not-allowed' : 'pointer' }}>
            {loading ? '⏳...' : editArticle ? '💾 Mettre à jour' : '🚀 Publier'}
          </button>
        </div>
      </form>
    </div>
  );
}

function Dashboard({ token, user, onLogout }) {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState('list');
  const [editArticle, setEditArticle] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  useEffect(() => { fetchArticles(); }, []);

  const fetchArticles = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/admin/articles`, { headers: { Authorization: `Bearer ${token}` } });
      const data = await res.json();
      setArticles(data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleDelete = async (id) => {
    try {
      await fetch(`${API_URL}/api/admin/articles/${id}`, { method: 'DELETE', headers: { Authorization: `Bearer ${token}` } });
      setArticles(prev => prev.filter(a => a.id !== id));
      setDeleteConfirm(null);
    } catch (err) { console.error(err); }
  };

  const handleSaved = (article) => {
    if (editArticle) { setArticles(prev => prev.map(a => a.id === article.id ? article : a)); }
    else { setArticles(prev => [article, ...prev]); }
    setView('list'); setEditArticle(null);
  };

  const published = articles.filter(a => a.published).length;
  const drafts = articles.filter(a => !a.published).length;

  return (
    <div style={{ minHeight: '100vh', background: '#0a0f0a', fontFamily: "'Segoe UI', sans-serif", color: '#e8e8e8' }}>
      <div style={{ background: 'rgba(0,0,0,0.5)', borderBottom: '1px solid rgba(0,200,0,0.15)', padding: '16px 30px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', position: 'sticky', top: 0, zIndex: 100 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <span style={{ fontSize: '1.5rem' }}>🔥</span>
          <div>
            <div style={{ color: '#ffd700', fontWeight: 800, fontSize: '1.1rem' }}>BBRS Morphix IT</div>
            <div style={{ color: '#555', fontSize: '0.8rem' }}>Tableau de bord</div>
          </div>
        </div>
        <div style={{ display: 'flex', gap: '12px' }}>
          <span style={{ background: 'rgba(0,200,0,0.1)', border: '1px solid rgba(0,200,0,0.2)', borderRadius: '20px', padding: '6px 14px', color: '#00cc00', fontSize: '0.85rem' }}>👤 {user.username}</span>
          <button onClick={onLogout} style={{ background: 'rgba(255,60,60,0.1)', border: '1px solid rgba(255,60,60,0.2)', borderRadius: '8px', padding: '8px 14px', color: '#ff6060', cursor: 'pointer', fontSize: '0.85rem' }}>Déconnexion</button>
        </div>
      </div>

      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '30px 20px' }}>
        {view === 'new' || view === 'edit' ? (
          <ArticleForm token={token} editArticle={editArticle} onSaved={handleSaved} onCancel={() => { setView('list'); setEditArticle(null); }} />
        ) : (
          <>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
              <h2 style={{ color: '#ffd700', fontSize: '1.4rem', fontWeight: 700, margin: 0 }}>📝 Mes articles</h2>
              <button onClick={() => setView('new')} style={{ background: 'linear-gradient(135deg, #00cc00, #007700)', color: '#fff', border: 'none', borderRadius: '10px', padding: '10px 20px', cursor: 'pointer', fontWeight: 700 }}>+ Nouvel article</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px', marginBottom: '30px' }}>
              {[['Total', articles.length, '#ffd700'], ['Publiés', published, '#00cc00'], ['Brouillons', drafts, '#ffcc00']].map(([label, num, color]) => (
                <div key={label} style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(0,200,0,0.1)', borderRadius: '12px', padding: '20px', textAlign: 'center' }}>
                  <div style={{ fontSize: '2rem', fontWeight: 800, color }}>{num}</div>
                  <div style={{ color: '#555', fontSize: '0.85rem', marginTop: '4px' }}>{label}</div>
                </div>
              ))}
            </div>
            {loading ? (
              <div style={{ textAlign: 'center', padding: '60px', color: '#555' }}>⏳ Chargement...</div>
            ) : articles.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '60px', color: '#555' }}>
                <div style={{ fontSize: '3rem', marginBottom: '12px' }}>📭</div>
                <p>Aucun article. Créez le premier !</p>
              </div>
            ) : (
              <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(0,200,0,0.1)', borderRadius: '14px', overflow: 'hidden' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr>{['TITRE', 'CATÉGORIE', 'STATUT', 'FICHIER', 'DATE', 'ACTIONS'].map(h => (
                      <th key={h} style={{ color: '#555', fontSize: '0.75rem', padding: '10px 12px', textAlign: 'left', borderBottom: '1px solid rgba(255,255,255,0.05)' }}>{h}</th>
                    ))}</tr>
                  </thead>
                  <tbody>
                    {articles.map(article => (
                      <tr key={article.id}>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)', color: '#e8e8e8', fontWeight: 600 }}>{article.title.length > 35 ? article.title.slice(0, 35) + '...' : article.title}</td>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)', color: '#888' }}>{article.category}</td>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                          <span style={{ background: article.published ? 'rgba(0,200,0,0.15)' : 'rgba(255,200,0,0.1)', color: article.published ? '#00cc00' : '#ffcc00', borderRadius: '20px', padding: '3px 10px', fontSize: '0.75rem', fontWeight: 600 }}>{article.published ? '✅ Publié' : '⏸️ Brouillon'}</span>
                        </td>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)', color: '#666' }}>{article.file ? '📎 Oui' : '—'}</td>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)', color: '#666', fontSize: '0.85rem' }}>{formatDate(article.createdAt)}</td>
                        <td style={{ padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                          <button onClick={() => { setEditArticle(article); setView('edit'); }} style={{ background: 'rgba(255,215,0,0.1)', color: '#ffd700', border: '1px solid rgba(255,215,0,0.2)', borderRadius: '7px', padding: '5px 12px', cursor: 'pointer', fontSize: '0.8rem', marginRight: '6px' }}>✏️</button>
                          <button onClick={() => setDeleteConfirm(article.id)} style={{ background: 'rgba(255,60,60,0.1)', color: '#ff6060', border: '1px solid rgba(255,60,60,0.2)', borderRadius: '7px', padding: '5px 12px', cursor: 'pointer', fontSize: '0.8rem' }}>🗑️</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </>
        )}
      </div>

      {deleteConfirm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: '#111', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '16px', padding: '30px', maxWidth: '360px', textAlign: 'center' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '12px' }}>🗑️</div>
            <h3 style={{ color: '#ff6060', marginBottom: '8px' }}>Supprimer l'article ?</h3>
            <p style={{ color: '#888', fontSize: '0.9rem', marginBottom: '24px' }}>Cette action est irréversible.</p>
            <div style={{ display: 'flex', gap: '12px', justifyContent: 'center' }}>
              <button onClick={() => setDeleteConfirm(null)} style={{ background: 'rgba(255,255,255,0.05)', color: '#aaa', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', padding: '10px 20px', cursor: 'pointer' }}>Annuler</button>
              <button onClick={() => handleDelete(deleteConfirm)} style={{ background: 'rgba(255,60,60,0.15)', color: '#ff6060', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '10px', padding: '10px 20px', cursor: 'pointer' }}>Supprimer</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default function Admin() {
  const [token, setToken] = useState(() => getToken());
  const [user, setUser] = useState(null);
  const [checking, setChecking] = useState(true);

  useEffect(() => {
    const t = getToken();
    if (t) {
      fetch(`${API_URL}/api/auth/me`, { headers: { Authorization: `Bearer ${t}` } })
        .then(r => r.json())
        .then(data => { if (data.user) { setToken(t); setUser(data.user); } else handleLogout(); })
        .catch(() => handleLogout())
        .finally(() => setChecking(false));
    } else {
      setChecking(false);
    }
  }, []);

  const handleLogin = (t, u) => { setToken(t); setUser(u); };
  const handleLogout = () => { clearToken(); setToken(null); setUser(null); };

  if (checking) return <div style={{ minHeight: '100vh', background: '#0a0f0a', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#ffd700', fontSize: '1.5rem' }}>🔥 Chargement...</div>;
  if (!token || !user) return <LoginForm onLogin={handleLogin} />;
  return <Dashboard token={token} user={user} onLogout={handleLogout} />;
}
